// Validate input and calculate shot count
const input = $input.item.json.body || $input.item.json;
const errors = [];

// Validation
if (!input.scene_id) errors.push("Missing required field: scene_id");
if (!input.narration_text) errors.push("Missing required field: narration_text");
if (!input.audio_duration && input.audio_duration !== 0) {
  errors.push("Missing required field: audio_duration");
}

if (errors.length > 0) {
  throw new Error("Validation failed: " + errors.join(", "));
}

// Calculate shot count based on audio duration
const duration = parseFloat(input.audio_duration);
let shotCount = 2;
if (duration >= 10 && duration <= 25) shotCount = 3;
if (duration > 25) shotCount = 4;

// Calculate duration per shot (evenly distributed)
const durationPerShot = Math.round((duration / shotCount) * 100) / 100;

return {
  scene_id: input.scene_id,
  narration_text: input.narration_text,
  audio_duration: duration,
  shot_count: shotCount,
  duration_per_shot: durationPerShot
};

const aiResponse = $input.item.json;
const validateData = $json;

let content =
  aiResponse.output ||
  aiResponse.choices?.[0]?.message?.content ||
  aiResponse.message?.content ||
  "";

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let shots;

try {
  shots = JSON.parse(content);
} catch {
  const sentences = validateData.narration_text.match(/[^.!?]+[.!?]+/g) || [validateData.narration_text];

  shots = sentences.slice(0, validateData.shot_count).map((s, i) => ({
    shot_num: i + 1,
    narration: s.trim()
  }));
}

while (shots.length < validateData.shot_count) {
  shots.push({
    shot_num: shots.length + 1,
    narration: ""
  });
}

shots = shots.slice(0, validateData.shot_count);

shots = shots.map((shot, index) => ({
  shot_num: index + 1,
  narration: shot.narration || shot.text || "",
  duration_seconds: validateData.duration_per_shot
}));

return {
  scene_id: validateData.scene_id,
  shots,
  total_duration: validateData.audio_duration
};
